const byCitySlug: Record<string, CityQualityProfileRecord> = {};
for (const profile of cityQualityProfiles) {
  byCitySlug[profile.citySlug] = profile;
}

/** Build-time integrity guard — throws (failing `next build`) on any invalid profile. */
function assertCityQualityIntegrity(
  profiles: readonly CityQualityProfileRecord[],
): void {
  const errors: string[] = [];
  const seen = new Set<string>();
  const inRange = (n: number) =>
    typeof n === "number" && Number.isFinite(n) && n >= 0 && n <= 100;
  for (const p of profiles) {
    if (!p.citySlug) errors.push(`missing citySlug`);
    if (seen.has(p.citySlug)) errors.push(`duplicate citySlug: ${p.citySlug}`);
    seen.add(p.citySlug);
    const scores = [
      p.safety.crimeScore, p.safety.personalSafetyScore, p.safety.nightSafetyScore,
      p.safety.roadSafetyScore, p.safety.overallSafetyScore,
      p.quality.qualityOfLifeScore, p.quality.healthcareScore, p.quality.educationScore,
      p.quality.greenSpaceScore, p.quality.cleanlinessScore, p.quality.infrastructureScore,
      p.quality.mobilityScore,
      p.lifestyle.familyFriendlyScore, p.lifestyle.digitalNomadScore,
      p.lifestyle.retirementScore, p.lifestyle.walkabilityScore,
      p.lifestyle.cyclingScore, p.lifestyle.outdoorLifestyleScore,
    ];
    if (scores.some((n) => !inRange(n)))
      errors.push(`${p.citySlug}: score out of range (0-100)`);
    const summaries = [
      p.safetySummary, p.qualitySummary, p.familySummary,
      p.nomadSummary, p.retirementSummary,
    ];
    if (summaries.some((t) => typeof t !== "string" || t.length === 0))
      errors.push(`${p.citySlug}: missing summary`);
  }
  if (errors.length > 0) {
    throw new Error(`city-quality integrity failure:\n${errors.join("\n")}`);
  }
}

assertCityQualityIntegrity(cityQualityProfiles);

export function getCityQuality(
  citySlug: string,
): CityQualityProfileRecord | undefined {
  return byCitySlug[citySlug];
}

export function hasCityQuality(citySlug: string): boolean {
  return Object.prototype.hasOwnProperty.call(byCitySlug, citySlug);
}

export function getAllCityQualityProfiles(): readonly CityQualityProfileRecord[] {
  return cityQualityProfiles;
}
